    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Contortionist Basics - 4w 5x/wk',
    'flexibility',
    5,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Contortionist Basics'
ON CONFLICT DO NOTHING;

